import React from 'react';
import { motion } from 'framer-motion';

interface PageTransitionProps {
  children: React.ReactNode;
  className?: string;
}

const PageTransition: React.FC<PageTransitionProps> = ({ children, className = '' }) => {
  // Deconstruction transition variants
  const pageVariants = {
    initial: {
      opacity: 0,
      scale: 0.8,
      z: -200,
      rotateX: 90,
    },
    animate: {
      opacity: 1,
      scale: 1,
      z: 0,
      rotateX: 0,
      transition: {
        type: 'spring',
        stiffness: 100,
        damping: 20,
        duration: 0.6,
      },
    },
    exit: {
      opacity: 0,
      scale: 1.2,
      z: 200,
      rotateX: -90,
      transition: {
        type: 'spring',
        stiffness: 100,
        damping: 20,
        duration: 0.4,
      },
    },
  };

  return (
    <motion.div
      className={`w-full ${className}`}
      initial="initial"
      animate="animate"
      exit="exit"
      variants={pageVariants}
      style={{ transformStyle: 'preserve-3d' }}
    >
      {children}
    </motion.div>
  );
};

export default PageTransition;
